#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool is_temperature_stale(controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_temperature || controller->last_temperature_ms == 0U) {
        return true;
    }
    return (now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static bool is_level_stale(controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_level || controller->last_level_ms == 0U) {
        return true;
    }
    return (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void apply_sensor_timeout(controller_t *controller)
{
    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->has_valid_level = false;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    if (controller == NULL) {
        return (controller_output_t){
            .inlet_open = false,
            .heater_on = false,
            .state = CONTROLLER_STATE_SAFE_IDLE,
            .state_name = "STATE SAFE_IDLE",
            .changed = false,
            .timed_out = false,
        };
    }

    controller_output_t output = {
        .inlet_open = controller->inlet_open,
        .heater_on = controller->heater_on,
        .state = controller->state,
        .state_name = controller_state_name(controller->state),
        .changed = false,
        .timed_out = false,
    };

    uint32_t now_ms = input.now_ms;
    bool was_timeout = is_temperature_stale(controller, now_ms) || is_level_stale(controller, now_ms);

    // Check for sensor timeout - force safe idle state
    if (was_timeout) {
        apply_sensor_timeout(controller);
        output.timed_out = true;
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.changed = true;
        return output;
    }

    // Check for invalid input - force safe idle state
    switch (input.kind) {
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        apply_sensor_timeout(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.changed = true;
        return output;
    }

    // Handle sensor timeout input explicitly
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        apply_sensor_timeout(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.changed = true;
        return output;
    }

    // Handle NONE input - maintain current state
    if (input.kind == CONTROLLER_INPUT_NONE) {
        output.inlet_open = controller->inlet_open;
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.changed = false;
        return output;
    }

    // Update sensor freshness
    bool temperature_freshened = false;
    bool level_freshened = false;

    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = now_ms;
        temperature_freshened = true;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = now_ms;
        level_freshened = true;
    }

    // Stay in safe all-off state until both sensors have been seen validly
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.changed = (controller->inlet_open != false) || (controller->heater_on != false) || 
                         (controller->state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    // Both sensors valid - apply control policy
    bool inlet_was_open = controller->inlet_open;
    bool heater_was_on = controller->heater_on;
    controller_state_t state_was = controller->state;

    // Control logic based on level and temperature
    if (controller->last_level < 60) {
        // Low level: open inlet, keep heater off
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (controller->last_level > 75) {
        // High level: close inlet
        controller->inlet_open = false;
    }

    // Heater control based on level and temperature
    // If LEVEL < 55 at any time, keep HEATER OFF
    if (controller->last_level < 55) {
        controller->heater_on = false;
    } else if (controller->last_level >= 60 && controller->last_level <= 75) {
        // In working level region - apply temperature-based heater control

        if (controller->last_temperature_c < 45) {
            // Safe level with low temp: close inlet and turn heater on
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (controller->last_temperature_c >= 45 && controller->last_temperature_c < 47) {
            // Near upper band, low temp: close inlet and hold previous safe heater state
            controller->inlet_open = false;
            // Keep previous heater state (should be off or just turned on)
            controller->state = CONTROLLER_STATE_HOLDING;
        } else if (controller->last_temperature_c >= 47 && controller->last_temperature_c <= 48) {
            // In early-off band - check temperature trend

            bool temp_rising = false;
            if (controller->previous_temperature_c != 0 && 
                controller->last_temperature_c > controller->previous_temperature_c) {
                temp_rising = true;
            }

            if (temp_rising) {
                // Temperature is rising: turn heater off early
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                // Temperature not rising: hold previous safe heater state
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        } else if (controller->last_temperature_c > 48) {
            // High temperature: close inlet and turn heater off
            controller->inlet_open = false;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.changed = (inlet_was_open != controller->inlet_open) || 
                     (heater_was_on != controller->heater_on) || 
                     (state_was != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

